const COLORS = ['#2f6df6','#e2497a','#1aa179','#f59e0b','#7c3aed','#0ea5e9','#ef4444','#10b981'];
function colorFor(n){let h=0;for(let i=0;i<n.length;i++)h=n.charCodeAt(i)+((h<<5)-h);return COLORS[Math.abs(h)%COLORS.length];}
function initials(n){return (n||'?').split(' ').slice(0,2).map(w=>w[0]||'').join('').toUpperCase();}
const rows = $input.all().map(i=>i.json).filter(r=>r && r.id);
const conversations = rows.map(r=>{const nm=r.name||r.phone||'?';return{id:String(r.id),contactId:r.ghl_contact_id||null,name:nm,phone:r.phone,avatar:{initials:initials(nm),color:colorFor(nm)},channel:r.channel||'whatsapp',lastMessage:r.last_message||'',lastMessageAt:Number(r.last_message_at)||0,lastDirection:r.last_direction||'in',lastStatus:r.last_status||'received',unreadCount:Number(r.unread_count)||0,starred:!!r.starred,status:r.status||'open',lastInbound:Number(r.last_inbound)||0,contact:{email:r.email||'',company:r.company||'',tags:r.tags||[],source:r.source||'',owner:r.owner||''}};});
return [{ json: { conversations } }];
